import{_ as e,o as i,c as o,a0 as l}from"./chunks/framework.ECMusB9M.js";const u=JSON.parse('{"title":"1. El mapa de posicionamiento: posicionarse para diferenciarse","description":"","frontmatter":{},"headers":[],"relativePath":"Fichas/docs/temario/FICHA_01.md","filePath":"Fichas/docs/temario/FICHA_01.md"}'),r={name:"Fichas/docs/temario/FICHA_01.md"};function s(t,a,d,n,c,p){return i(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="_1-el-mapa-de-posicionamiento-posicionarse-para-diferenciarse" tabindex="-1">1. El mapa de posicionamiento: posicionarse para diferenciarse <a class="header-anchor" href="#_1-el-mapa-de-posicionamiento-posicionarse-para-diferenciarse" aria-label="Permalink to &quot;1. El mapa de posicionamiento: posicionarse para diferenciarse&quot;">​</a></h1><p>Es una <strong>herramienta de marketing</strong> que permite saber en qué situación se encuentra nuestra empresa respecto a la competencia en la <strong>mente del consumidor</strong>, de forma gráfica (<code>mapa</code>).</p><h2 id="_1-1-importancia-y-subjetividad-del-mapa" tabindex="-1">1.1. Importancia y subjetividad del mapa <a class="header-anchor" href="#_1-1-importancia-y-subjetividad-del-mapa" aria-label="Permalink to &quot;1.1. Importancia y subjetividad del mapa&quot;">​</a></h2><ul><li>Todo <code>mapa de posicionamiento</code> es <strong>subjetivo</strong>: refleja la percepción de cada consumidor.</li><li>Diferentes clientes pueden generar mapas distintos; lo importante es buscar el que sea <strong>estadísticamente más común</strong>.</li></ul><h2 id="_1-2-ejes-del-mapa" tabindex="-1">1.2. Ejes del mapa <a class="header-anchor" href="#_1-2-ejes-del-mapa" aria-label="Permalink to &quot;1.2. Ejes del mapa&quot;">​</a></h2><ul><li>El mapa consiste en <strong>dos ejes</strong> (<code>vertical</code> y <code>horizontal</code>) que se cruzan.</li><li>En los extremos de cada eje se sitúan los valores <strong>máximos</strong> y <strong>mínimos</strong>.</li></ul><h3 id="_1-2-1-variables-habituales" tabindex="-1">1.2.1. Variables habituales <a class="header-anchor" href="#_1-2-1-variables-habituales" aria-label="Permalink to &quot;1.2.1. Variables habituales&quot;">​</a></h3><ul><li>Lo habitual: <ul><li>Eje Y: <code>Precio</code></li><li>Eje X: <code>Calidad</code></li></ul></li><li>También se pueden usar otras variables importantes: <ul><li><code>Diseño</code></li><li><code>Fiabilidad</code></li><li>etc.</li></ul></li></ul><h3 id="_1-2-2-cuadrantes-del-mapa" tabindex="-1">1.2.2. Cuadrantes del mapa <a class="header-anchor" href="#_1-2-2-cuadrantes-del-mapa" aria-label="Permalink to &quot;1.2.2. Cuadrantes del mapa&quot;">​</a></h3><p>Si se utilizan <code>precio</code> y <code>calidad</code>:</p><ol><li>Calidad alta - Precio alto</li><li>Calidad alta - Precio bajo</li><li>Calidad baja - Precio alto</li><li>Calidad baja - Precio bajo</li></ol><ul><li>Normalmente los productos se colocan en diagonal (alta-alta / baja-baja), aunque la realidad puede variar: <ul><li>Un producto puede ser caro pero percibirse de <strong>mala calidad</strong>.</li><li>Un producto puede ser de <strong>alta calidad y buen precio</strong>.</li></ul></li><li>Existe un 5º cuadrante en el <strong>centro</strong>: <ul><li>No destaca ni en calidad ni en precio.</li><li>Se recomienda evitarlo, ya que tiende a desaparecer del mercado.</li></ul></li></ul><h2 id="_1-3-estrategia-de-posicionamiento" tabindex="-1">1.3. Estrategia de posicionamiento <a class="header-anchor" href="#_1-3-estrategia-de-posicionamiento" aria-label="Permalink to &quot;1.3. Estrategia de posicionamiento&quot;">​</a></h2><ol><li>Una vez establecidos los cuadrantes, se pueden situar: <ul><li>Las empresas de la <strong>competencia</strong></li><li>Nuestra propia empresa</li></ul></li><li>Identificar <strong>espacios desocupados</strong> como objetivos empresariales: <ul><li>Ejemplo: cuadrante <strong>calidad alta - precio bajo</strong><ul><li>Estrategia: posicionarnos en este cuadrante.</li><li>Casos reales: <code>Decathlon</code>, <code>Ikea</code> (ofreciendo calidad medio-alta a precio medio-bajo).</li></ul></li></ul></li></ol><h2 id="_1-4-ejemplo-practico" tabindex="-1">1.4. Ejemplo práctico <a class="header-anchor" href="#_1-4-ejemplo-practico" aria-label="Permalink to &quot;1.4. Ejemplo práctico&quot;">​</a></h2><ul><li>Mapa de posicionamiento de marcas de <code>tablets</code>: <ul><li>Eje Y: <code>Precio</code></li><li>Eje X: <code>Calidad</code></li><li>Permite visualizar dónde se sitúan diferentes marcas y detectar oportunidades de posicionamiento.</li></ul></li></ul>',16)])])}const h=e(r,[["render",s]]);export{u as __pageData,h as default};
